import{_ as a,o as d,c as o,ai as c}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Cron Add 加固","description":"","frontmatter":{"last_updated":"2026-01-05","owner":"opensoul","status":"complete","summary":"加固 cron.add 输入处理，对齐 schema，改进 cron UI/智能体工具","title":"Cron Add 加固","x-i18n":{"generated_at":"2026-02-03T07:47:26Z","model":"claude-opus-4-5","provider":"pi","source_hash":"d7e469674bd9435b846757ea0d5dc8f174eaa8533917fc013b1ef4f82859496d","source_path":"experiments/plans/cron-add-hardening.md","workflow":15}},"headers":[],"relativePath":"zh-CN/experiments/plans/cron-add-hardening.md","filePath":"zh-CN/experiments/plans/cron-add-hardening.md","lastUpdated":1771906665000}'),r={name:"zh-CN/experiments/plans/cron-add-hardening.md"};function n(l,e,i,s,t,h){return d(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="cron-add-加固-schema-对齐" tabindex="-1"><a class="header-anchor" href="#cron-add-加固-schema-对齐">#</a> Cron Add 加固 &amp; Schema 对齐</h1><h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景">#</a> 背景</h2><p>最近的 Gateway 网关日志显示重复的 <code>cron.add</code> 失败，参数无效（缺少 <code>sessionTarget</code>、<code>wakeMode</code>、<code>payload</code>，以及格式错误的 <code>schedule</code>）。这表明至少有一个客户端（可能是智能体工具调用路径）正在发送包装的或部分指定的任务负载。另外，TypeScript 中的 cron 提供商枚举、Gateway 网关 schema、CLI 标志和 UI 表单类型之间存在漂移，加上 <code>cron.status</code> 的 UI 不匹配（期望 <code>jobCount</code> 而 Gateway 网关返回 <code>jobs</code>）。</p><h2 id="目标" tabindex="-1"><a class="header-anchor" href="#目标">#</a> 目标</h2><ul><li>通过规范化常见的包装负载并推断缺失的 <code>kind</code> 字段来停止 <code>cron.add</code> INVALID_REQUEST 垃圾。</li><li>在 Gateway 网关 schema、cron 类型、CLI 文档和 UI 表单之间对齐 cron 提供商列表。</li><li>使智能体 cron 工具 schema 明确，以便 LLM 生成正确的任务负载。</li><li>修复 Control UI cron 状态任务计数显示。</li><li>添加测试以覆盖规范化和工具行为。</li></ul><h2 id="非目标" tabindex="-1"><a class="header-anchor" href="#非目标">#</a> 非目标</h2><ul><li>更改 cron 调度语义或任务执行行为。</li><li>添加新的调度类型或 cron 表达式解析。</li><li>除了必要的字段修复外，不大改 cron 的 UI/UX。</li></ul><h2 id="发现-当前差距" tabindex="-1"><a class="header-anchor" href="#发现-当前差距">#</a> 发现（当前差距）</h2><ul><li>Gateway 网关中的 <code>CronPayloadSchema</code> 排除了 <code>signal</code> + <code>imessage</code>，而 TS 类型包含它们。</li><li>Control UI CronStatus 期望 <code>jobCount</code>，但 Gateway 网关返回 <code>jobs</code>。</li><li>智能体 cron 工具 schema 允许任意 <code>job</code> 对象，导致格式错误的输入。</li><li>Gateway 网关严格验证 <code>cron.add</code> 而不进行规范化，因此包装的负载会失败。</li></ul><h2 id="变更内容" tabindex="-1"><a class="header-anchor" href="#变更内容">#</a> 变更内容</h2><ul><li><code>cron.add</code> 和 <code>cron.update</code> 现在规范化常见的包装形式并推断缺失的 <code>kind</code> 字段。</li><li>智能体 cron 工具 schema 与 Gateway 网关 schema 匹配，减少无效负载。</li><li>提供商枚举在 Gateway 网关、CLI、UI 和 macOS 选择器之间对齐。</li><li>Control UI 使用 Gateway 网关的 <code>jobs</code> 计数字段显示状态。</li></ul><h2 id="当前行为" tabindex="-1"><a class="header-anchor" href="#当前行为">#</a> 当前行为</h2><ul><li>**规范化：**包装的 <code>data</code>/<code>job</code> 负载被解包；<code>schedule.kind</code> 和 <code>payload.kind</code> 在安全时被推断。</li><li>**默认值：**当缺失时，为 <code>wakeMode</code> 和 <code>sessionTarget</code> 应用安全默认值。</li><li>**提供商：**Discord/Slack/Signal/iMessage 现在在 CLI/UI 中一致显示。</li></ul><p>参见 <a href="/docs/automation/cron-jobs">Cron 任务</a> 了解规范化的形式和示例。</p><h2 id="验证" tabindex="-1"><a class="header-anchor" href="#验证">#</a> 验证</h2><ul><li>观察 Gateway 网关日志中 <code>cron.add</code> INVALID_REQUEST 错误是否减少。</li><li>确认 Control UI cron 状态在刷新后显示任务计数。</li></ul><h2 id="可选后续工作" tabindex="-1"><a class="header-anchor" href="#可选后续工作">#</a> 可选后续工作</h2><ul><li>手动 Control UI 冒烟测试：为每个提供商添加一个 cron 任务 + 验证状态任务计数。</li></ul><h2 id="开放问题" tabindex="-1"><a class="header-anchor" href="#开放问题">#</a> 开放问题</h2><ul><li><code>cron.add</code> 是否应该接受来自客户端的显式 <code>state</code>（当前被 schema 禁止）？</li><li>我们是否应该允许 <code>webchat</code> 作为显式投递提供商（当前在投递解析中被过滤）？</li></ul>',20)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
